interface InputProps {
  name: string;
  type: string;

  [key: string]: string;
}

export default function Input({ name, type, ...props }: InputProps) {
  return (
    <>
      <input
        className="bg-transparent border border-purple-400 rounded"
        id={name}
        name={name}
        type={type}
        {...props}
        required
      />
    </>
  );
}
